5: // V42 ensures that when a field is hidden from visualization, it is also hidden from tooltips.
6: //
7: // This migration addresses the inconsistency where fields could be hidden from visualizations
8: // (hideFrom.viz = true) but would still appear in tooltips. To prevent user confusion and ensure
9: // consistent behavior, this migration automatically sets hideFrom.tooltip = true for any field
10: // configuration override that has hideFrom.viz = true.
11: //
12: // The migration specifically targets field configuration overrides, including the special
13: // __systemRef override, and updates the hideFrom object to include tooltip: true whenever
14: // viz: true is found.
15: //
16: // Example transformation:
17: //
18: // Before migration:
19: //
20: //	fieldConfig: {
21: //	  overrides: [{
22: //	    properties: [{
23: //	      id: "custom.hideFrom",
24: //	      value: { viz: true }
25: //	    }]
26: //	  }]
27: //	}
28: //
29: // After migration:
30: //
31: //	fieldConfig: {
32: //	  overrides: [{
33: //	    properties: [{
34: //	      id: "custom.hideFrom",
35: //	      value: { viz: true, tooltip: true }
36: //	    }]
37: //	  }]
38: //	}
39: func V42(_ context.Context, dash map[string]interface{}) error {
40: 	dash["schemaVersion"] = int(42)
41: 
42: 	// Get panels from dashboard
43: 	panels, ok := dash["panels"].([]interface{})
44: 	if !ok {
45: 		return nil
46: 	}
47: 
48: 	// Process each panel
49: 	for _, panelInterface := range panels {
50: 		panel, ok := panelInterface.(map[string]interface{})
51: 		if !ok {
52: 			continue
53: 		}
54: 
55: 		migrateHideFromForPanel(panel)
56: 	}
57: 
58: 	return nil
59: }
60: 
61: // migrateHideFromForPanel processes a single panel and its nested panels
62: func migrateHideFromForPanel(panel map[string]interface{}) {
63: 	// Process the panel's field config
64: 	if fieldConfig, ok := panel["fieldConfig"].(map[string]interface{}); ok {
65: 		if overrides, ok := fieldConfig["overrides"].([]interface{}); ok {
66: 			for _, overrideInterface := range overrides {
67: 				override, ok := overrideInterface.(map[string]interface{})
68: 				if !ok {
69: 					continue
70: 				}
71: 
72: 				if properties, ok := override["properties"].([]interface{}); ok {
73: 					for _, propertyInterface := range properties {
74: 						property, ok := propertyInterface.(map[string]interface{})
75: 						if !ok {
76: 							continue
77: 						}
78: 
79: 						// Check if this is a custom.hideFrom property
80: 						if id := GetStringValue(property, "id"); id == "custom.hideFrom" {
81: 							if value, ok := property["value"].(map[string]interface{}); ok {
82: 								// If viz is true, also set tooltip to true
83: 								if GetBoolValue(value, "viz") {
84: 									value["tooltip"] = true
85: 								}
86: 							}
87: 						}
88: 					}
89: 				}
90: 			}
91: 		}
92: 	}
93: 
94: 	// Process nested panels (for rows)
95: 	if nestedPanels, ok := panel["panels"].([]interface{}); ok {
96: 		for _, nestedPanelInterface := range nestedPanels {
97: 			if nestedPanel, ok := nestedPanelInterface.(map[string]interface{}); ok {
98: 				migrateHideFromForPanel(nestedPanel)
99: 			}
100: 		}
101: 	}
102: }
